package com.example.configservice

import scala.xml.XML
import scala.xml.Elem
import scala.io.Source
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.model.StatusCodes
import akka.stream.ActorMaterializer

object ConfigService extends App {
  implicit val system: ActorSystem = ActorSystem("configService")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  def extractSettings(xmlString: String): Map[String, String] = {
    val xml: Elem = XML.loadString(xmlString)
    val settings = (xml \\ "setting").map { setting =>
      val key = (setting \ "@name").text
      val value = setting.text
      key -> value
    }
    settings.toMap
  }

  val route =
    path("parseConfig") {
      post {
        entity(as[String]) { xmlString =>
          try {
            val settings = extractSettings(xmlString)
            complete(settings.toString())
          } catch {
            case ex: Exception =>
              complete(StatusCodes.BadRequest, s"Invalid XML: ${ex.getMessage}")
          }
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
}